// Resize + compress an uploaded image client-side so proof photos stay small enough
// to save reliably (storage values are capped at 5MB, and phone photos routinely exceed that).
function compressImageFile(file, maxWidth = 1000, quality = 0.65) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("Couldn't read that file."));
    reader.onload = () => {
      const img = new window.Image();
      img.onerror = () => reject(new Error("That doesn't look like a valid image."));
      img.onload = () => {
        const scale = Math.min(1, maxWidth / img.width);
        const canvas = document.createElement("canvas");
        canvas.width = Math.round(img.width * scale);
        canvas.height = Math.round(img.height * scale);
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL("image/jpeg", quality));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

const PROOF_KEY = (fixtureId) => `eafc26-proof-${fixtureId}`;

// Every transfer goes through a two-stage ratification: the selling side is settled after
// 12 hours, but the buying side (the actual signing — squad placement, budget hit, tax) only
// becomes official after the full 24 hours.
const SELLER_CREDIT_MS = 12 * 60 * 60 * 1000;
const BUYER_RATIFY_MS = 24 * 60 * 60 * 1000;

function transferStatus(tx, nowMs) {
  if (tx.cancelled) return { label: "Cancelled", tone: "red" };
  const created = tx.createdAt || 0;
  const sellerDone = tx.sellerProcessed || nowMs - created >= SELLER_CREDIT_MS;
  const buyerDone = tx.buyerProcessed || nowMs - created >= BUYER_RATIFY_MS;
  if (buyerDone) return { label: "Ratified", tone: "green" };
  if (sellerDone) return { label: `Seller credited — buyer ratifies in ${formatCountdown(created + BUYER_RATIFY_MS - nowMs)}`, tone: "gold" };
  return { label: `Pending — seller credited in ${formatCountdown(created + SELLER_CREDIT_MS - nowMs)}`, tone: "muted" };
}

const N_TEAMS = 10;
// Only 8 of the 10 team slots are actually being used this season — these two were never claimed
// and have no data. Filtered out at load time everywhere teams are read, without touching N_TEAMS
// itself or anything downstream that depends on it, since this app is in active mid-season use.
// To bring a team back, just remove its id from this list.
const HIDDEN_TEAM_IDS = ["T8", "T10"];
const STARTER_SLOTS = 21;
const MIN_U21_PLAYERS = 5; // at least this many players aged 20 or under, somewhere in the squad
const RESERVE_SLOTS = 5;
const BASE_WAGE_CAP = 1.5;
const BASE_BUDGET = 600;
const NEXT_CAP_MAX = 2.8; // £M for 1st place
const NEXT_CAP_FLOOR = 1.8; // £M for last place — flattened range so winning doesn't compound the wage advantage

function nextSeasonCap(position, nTeams) {
  const step = nTeams > 1 ? (NEXT_CAP_MAX - NEXT_CAP_FLOOR) / (nTeams - 1) : 0;
  const cap = NEXT_CAP_MAX - (position - 1) * step;
  return +Math.max(cap, NEXT_CAP_FLOOR).toFixed(2);
}

// End-of-season budget top-up: scales by final position, top team gets the most.
// Hand-tuned to land on clean round numbers (ending in 0 or 5) rather than perfectly even steps.
// Season-end wage cap change: adds a bonus ON TOP of whatever a team's current wage cap already
// is (so it compounds season over season), rather than resetting the whole cap by position like
// nextSeasonCap used to. Scales linearly from +£300k for 1st down to +£50k for last place.
const SEASON_WAGE_BONUS_MAX = 0.3; // £M for 1st place
const SEASON_WAGE_BONUS_MIN = 0.05; // £M for last place

// Cup prizes - budget in £M, wage in £M (both compound onto the team's current wage cap, same as
// the season-end bonus, since the wage bonus is meant to be a lasting reward, not a one-off).
const CUP_WINNER_BUDGET = 25;
const CUP_WINNER_WAGE = 0.1;
const CUP_RUNNERUP_BUDGET = 10;
const CUP_RUNNERUP_WAGE = 0.04;

// Sponsorship deals: assigned once per season, meant for the halfway point. Expected position
// blends current league position (weighted more heavily) with squad quality (value + rating).
const SPONSOR_POSITION_WEIGHT = 0.65;
const SPONSOR_QUALITY_WEIGHT = 0.35;
const SPONSOR_BONUS_BUDGET = 50;
const SPONSOR_BONUS_WAGE = 0.1;
const SPONSOR_COMPANIES = [
  "Nike", "Adidas", "Emirates", "Pepsi", "Coca-Cola", "Rolex", "Heineken", "Puma",
  "Amazon", "Samsung", "Visa", "Red Bull", "Under Armour", "Gillette", "Hyundai", "Qatar Airways",
];

function seasonWageBonus(position, nTeams) {
  if (nTeams <= 1) return SEASON_WAGE_BONUS_MAX;
  const raw = SEASON_WAGE_BONUS_MAX - (position - 1) * (SEASON_WAGE_BONUS_MAX - SEASON_WAGE_BONUS_MIN) / (nTeams - 1);
  return +raw.toFixed(3);
}

const SEASON_BOOST_MAX = 120; // £M for 1st place
const SEASON_BOOST_MIN = 40;  // £M for last place
const SEASON_BOOST_TABLE_10 = [120, 110, 100, 90, 80, 70, 60, 50, 45, 40];

function seasonBudgetBoost(position, nTeams) {
  if (nTeams === SEASON_BOOST_TABLE_10.length && position >= 1 && position <= nTeams) {
    return SEASON_BOOST_TABLE_10[position - 1];
  }
  if (nTeams <= 1) return SEASON_BOOST_MAX;
  const raw = SEASON_BOOST_MAX - (position - 1) * (SEASON_BOOST_MAX - SEASON_BOOST_MIN) / (nTeams - 1);
  return Math.round(raw / 5) * 5; // fall back to the nearest £5M for any other league size
}

