const STORAGE_KEY = "eafc26-league-state-v1";
const DM_STORAGE_KEY = "eafc26-private-messages-v1"; // saved separately so it can't be clobbered by unrelated saves
const CHAT_STORAGE_KEY = "eafc26-league-chat-v1"; // same isolation as private messages, for the same reason
// Squads get isolated per-team rather than one shared key — editing your own squad, reordering your
// XI, or signing a player should never be at risk of being clobbered by an unrelated save happening
// on someone else's team at the same moment.
const squadKeyFor = (teamId) => `eafc26-squad-${teamId}-v1`;
// Same isolation, extended to the other high-traffic, multi-person-writing-at-once data.
const AUCTIONS_STORAGE_KEY = "eafc26-auctions-v1";
const TRANSFER_LISTINGS_STORAGE_KEY = "eafc26-transfer-listings-v1";
const WANTED_LISTINGS_STORAGE_KEY = "eafc26-wanted-listings-v1";
const teamKeyFor = (teamId) => `eafc26-team-${teamId}-v1`;
// The draft is specifically designed for every team to edit their own picks at the same time —
// exactly the pattern that's caused every previous "shared blob" bug, so it gets the same per-team
// isolation as squads/teams. Player database gets its own single key too, merge-based (like chat),
// since concurrent re-imports should only ever add/update players, never risk silently dropping ones
// that aren't in whichever snapshot happens to save last.
const draftKeyFor = (teamId) => `eafc26-draft-${teamId}-v1`;
const PLAYERDB_STORAGE_KEY = "eafc26-player-database-v1";
// The admin PIN gets its own dedicated key — it's the "keys to the kingdom," and it's exactly what
// just got wiped when a stale browser overwrote the whole shared blob back to defaults.
const ADMIN_PIN_STORAGE_KEY = "eafc26-admin-pin-v1";
// Blind bids need extra care beyond simple isolation — multiple teams submit bids to the SAME
// record around the same time, which is exactly the "several people editing the same shared thing
// at once" pattern that's caused every previous sync bug in this app.
const BLINDBIDS_STORAGE_KEY = "eafc26-blindbids-v1";
// Transfers was still part of the shared blob — mostly-additive records with unique IDs, so this
// uses merge-by-id (like chat/messages), ensuring a stale browser overwriting this can only ever
// add/update records, never silently drop ones (like tax-bearing entries) that aren't in its copy.
const TRANSFERS_STORAGE_KEY = "eafc26-transfers-v1";

// Chat and private messages are append-only — merging by id (rather than replacing the whole
// array) means an incoming sync can only ever add messages, never accidentally erase one that's
// already visible locally, regardless of exact timing between saves and syncs.
function mergeMessagesById(local, incoming) {
  const byId = new Map(local.map((m) => [m.id, m]));
  (incoming || []).forEach((m) => byId.set(m.id, m));
  return Array.from(byId.values()).sort((a, b) => a.time - b.time);
}
