// Type a name, get matches from the imported player database (Sofifa), pick one to
// auto-fill position/rating/club/age/wage/value on whatever form it's plugged into.
function PlayerAutocomplete({ value, onChange, onSelect, playerDatabase, placeholder }) {
  const [open, setOpen] = useState(false);
  const [dropdownRect, setDropdownRect] = useState(null);
  const boxRef = useRef(null);
  const dropdownRef = useRef(null); // the portal-rendered dropdown lives outside boxRef's DOM subtree

  const matches = useMemo(() => {
    const q = (value || "").trim().toLowerCase();
    if (!q || !playerDatabase || playerDatabase.length === 0) return [];
    return playerDatabase.filter((p) => p.name.toLowerCase().includes(q)).slice(0, 8);
  }, [value, playerDatabase]);

  const updateDropdownPosition = () => {
    if (boxRef.current) {
      const rect = boxRef.current.getBoundingClientRect();
      setDropdownRect({ top: rect.bottom + 4, left: rect.left, width: rect.width });
    }
  };

  useEffect(() => {
    // Since the dropdown renders via a portal (outside boxRef's own DOM subtree, to escape any
    // clipped/backdrop-filtered parent), a click on the dropdown itself would otherwise look like
    // a click "outside" boxRef - closing it via mousedown before the button's own click/onSelect
    // ever gets a chance to fire. Checking dropdownRef too is what actually lets selection work.
    const onClickOutside = (e) => {
      const inBox = boxRef.current && boxRef.current.contains(e.target);
      const inDropdown = dropdownRef.current && dropdownRef.current.contains(e.target);
      if (!inBox && !inDropdown) setOpen(false);
    };
    document.addEventListener("mousedown", onClickOutside);
    window.addEventListener("scroll", updateDropdownPosition, true);
    window.addEventListener("resize", updateDropdownPosition);
    return () => {
      document.removeEventListener("mousedown", onClickOutside);
      window.removeEventListener("scroll", updateDropdownPosition, true);
      window.removeEventListener("resize", updateDropdownPosition);
    };
  }, []);

  return (
    <div ref={boxRef} style={{ position: "relative" }}>
      <TextInput
        placeholder={placeholder || "Start typing a player name…"}
        value={value}
        onChange={(e) => { onChange(e.target.value); setOpen(true); updateDropdownPosition(); }}
        onFocus={() => { setOpen(true); updateDropdownPosition(); }}
      />
      {open && matches.length > 0 && dropdownRect && createPortal(
        <div ref={dropdownRef} style={{
          position: "fixed", top: dropdownRect.top, left: dropdownRect.left, width: dropdownRect.width, zIndex: 10000,
          background: C.panel, border: `1px solid ${C.border}`, borderRadius: 8,
          maxHeight: 220, overflowY: "auto", boxShadow: "0 8px 20px rgba(0,0,0,0.4)",
        }}>
          {matches.map((p) => (
            <button key={`${p.name}::${p.club}`} onClick={() => { onSelect(p); setOpen(false); }}
              className="flex items-center justify-between"
              style={{ width: "100%", textAlign: "left", background: "transparent", border: "none", borderBottom: `1px solid ${C.border}33`, padding: "8px 10px", cursor: "pointer", color: C.text, fontSize: 12.5 }}>
              <span>{p.name}</span>
              <span style={{ color: C.muted, fontSize: 11 }}>{p.position} · {p.rating} OVR{p.club ? ` · ${p.club}` : ""}</span>
            </button>
          ))}
        </div>,
        document.body
      )}
    </div>
  );
}

// A simple, reliable click-to-select dropdown for club names — same pattern as PlayerAutocomplete
// above. Deliberately not using a native <input list>/<datalist>, since that combination has known
// cross-browser quirks with fully React-controlled inputs where a selection doesn't stick.
function ClubAutocomplete({ value, onChange, options, placeholder }) {
  const [open, setOpen] = useState(false);
  const boxRef = useRef(null);

  const matches = useMemo(() => {
    const q = (value || "").trim().toLowerCase();
    if (!options || options.length === 0) return [];
    const filtered = q ? options.filter((c) => c.toLowerCase().includes(q)) : options;
    return filtered.slice(0, 8);
  }, [value, options]);

  useEffect(() => {
    const onClickOutside = (e) => {
      if (boxRef.current && !boxRef.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", onClickOutside);
    return () => document.removeEventListener("mousedown", onClickOutside);
  }, []);

  return (
    <div ref={boxRef} style={{ position: "relative" }}>
      <TextInput
        placeholder={placeholder}
        value={value}
        onChange={(e) => { onChange(e.target.value); setOpen(true); }}
        onFocus={() => setOpen(true)}
      />
      {open && matches.length > 0 && (
        <div style={{
          position: "absolute", top: "calc(100% + 4px)", left: 0, right: 0, zIndex: 20,
          background: C.panel, border: `1px solid ${C.border}`, borderRadius: 8,
          maxHeight: 220, overflowY: "auto", boxShadow: "0 8px 20px rgba(0,0,0,0.4)",
        }}>
          {matches.map((c) => (
            <button key={c} onClick={() => { onChange(c); setOpen(false); }}
              style={{ width: "100%", textAlign: "left", background: "transparent", border: "none", borderBottom: `1px solid ${C.border}33`, padding: "8px 10px", cursor: "pointer", color: C.text, fontSize: 12.5 }}>
              {c}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function Btn({ children, onClick, variant = "primary", size = "md", icon: Icon, disabled, style, title }) {
  const base = {
    display: "inline-flex", alignItems: "center", gap: 6, justifyContent: "center",
    borderRadius: 9, fontWeight: 700, cursor: disabled ? "not-allowed" : "pointer",
    border: "1px solid transparent", transition: "opacity .15s", opacity: disabled ? 0.5 : 1,
    fontSize: size === "sm" ? 12.5 : 13.5, padding: size === "sm" ? "6px 10px" : "8px 14px",
    whiteSpace: "nowrap",
  };
  const variants = {
    primary: { background: C.gold, color: C.dark },
    outline: { background: "transparent", color: C.text, border: `1px solid ${C.border}` },
    danger: { background: "transparent", color: C.red, border: `1px solid ${C.red}55` },
    ghost: { background: "transparent", color: C.muted },
  };
  return (
    <button title={title} disabled={disabled} onClick={onClick} style={{ ...base, ...variants[variant], ...style }}>
      {Icon && <Icon size={14} />}
      {children}
    </button>
  );
}

// Small "this player is the Club Captain" marker — shown beside their name wherever they appear.
// Colour-codes a stat 0-99 the way FIFA/EAFC cards do — green for elite, down to red for weak.
function statColor(v) {
  const n = Number(v) || 0;
  if (n >= 85) return "#3ddc84";
  if (n >= 70) return "#e7c568";
  if (n >= 55) return "#e0a050";
  return "#e05a5a";
}

function StatBar({ label, value }) {
  if (value == null) return null;
  const n = Number(value) || 0;
  return (
    <div style={{ marginBottom: 8 }}>
      <div className="flex items-center justify-between" style={{ fontSize: 11, marginBottom: 3 }}>
        <span style={{ color: C.muted, textTransform: "uppercase", letterSpacing: "0.03em" }}>{label}</span>
        <span style={{ color: statColor(n), fontWeight: 800 }}>{n}</span>
      </div>
      <div style={{ background: `${C.border}55`, borderRadius: 4, height: 6, overflow: "hidden" }}>
        <div style={{ width: `${Math.min(n, 99)}%`, height: "100%", background: statColor(n), borderRadius: 4 }} />
      </div>
    </div>
  );
}

